    fn link_provenance(
        source_path: &Utf8Path,
        command_start: usize,
        command_end: usize,
        text_start: usize,
        text_end: usize,
        target_span: Option<(usize, usize)>,
    ) -> SourceProvenance {
        Self::link_provenance_with_spans(
            source_path,
            command_start,
            command_end,
            RenderMacroDefinitionSpan {
                path: source_path.to_owned(),
                start_utf8: text_start,
                end_utf8: text_end,
            },
            target_span.map(|(target_start, target_end)| RenderMacroDefinitionSpan {
                path: source_path.to_owned(),
                start_utf8: target_start,
                end_utf8: target_end,
            }),
        )
    }

    fn link_provenance_with_spans(
        source_path: &Utf8Path,
        command_start: usize,
        command_end: usize,
        text_span: RenderMacroDefinitionSpan,
        target_span: Option<RenderMacroDefinitionSpan>,
    ) -> SourceProvenance {
        let mut provenance = SourceProvenance::file(
            text_span.path,
            text_span.start_utf8 as u32,
            text_span.end_utf8 as u32,
        )
        .with_related(
            SourceSpanRole::Invocation,
            ProvenanceSpan::File(SourceSpan {
                path: source_path.to_owned(),
                start_utf8: command_start as u32,
                end_utf8: command_end as u32,
            }),
        );
        if let Some(target_span) = target_span {
            provenance = provenance.with_related(
                SourceSpanRole::Argument,
                ProvenanceSpan::File(SourceSpan {
                    path: target_span.path,
                    start_utf8: target_span.start_utf8 as u32,
                    end_utf8: target_span.end_utf8 as u32,
                }),
            );
        }
        provenance
    }

    fn capture_legacy_graphic_event(
        &mut self,
        source_path: &Utf8Path,
        source: &str,
        command_start: usize,
        argument_index: usize,
        limit: usize,
        graphic_paths: &[Utf8PathBuf],
        graphic_extensions: &[String],
        default_options: Option<&str>,
        inherited_options: Option<&str>,
    ) -> Option<usize> {
        let argument_index = skip_ascii_whitespace(source, argument_index);
        let Some((options, _, _, after)) = read_braced_source_argument(source, argument_index)
        else {
            return None;
        };
        if after > limit {
            return None;
        }
        let options = options.trim().to_string();
        let path = options.split(',').find_map(|part| {
            let (key, value) = part.split_once('=')?;
            match key.trim() {
                "file" | "figure" => {
                    let value = value.trim();
                    (!value.is_empty()).then_some(value)
                }
                _ => None,
            }
        });
        if let Some(path) = path {
            let resolved_path = self.resolve_graphic_asset_path(
                source_path,
                path,
                graphic_paths,
                graphic_extensions,
            );
            let resolved_asset_path = Utf8Path::new(&resolved_path);
            let asset_format = GraphicAssetFormat::from_path(&resolved_path);
            let asset_hash = self.project_file_hash(resolved_asset_path);
            let asset_dimensions =
                self.project_graphic_asset_dimensions(resolved_asset_path, asset_format);
            let event_source =
                SourceProvenance::file(source_path.to_owned(), command_start as u32, after as u32);
            let options = merge_graphic_default_options(
                default_options,
                merge_graphic_options(Some(options), inherited_options),
            );
            self.emit_render_event(
                RenderEvent::GraphicRef(GraphicRefEvent {
                    asset_format,
                    asset_hash: asset_hash.clone(),
                    asset_dimensions,
                    path: resolved_path.clone(),
                    options,
                }),
                event_source.clone(),
            );
            self.emit_missing_graphic_asset_diagnostic(
                &resolved_path,
                asset_hash.as_deref(),
                event_source,
            );
        }
        Some(after)
    }

