    #[test]
    fn class_and_package_files_lex_at_letter_control_words() {
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.mount_file(
            "wrapper.cls",
            r"\def\class@mark{class}\def\classcall{\class@mark}",
        );
        vm.mount_file("pkg.sty", r"\def\pkg@mark{pkg}\def\pkgcall{\pkg@mark}");

        let outcome = vm.run_plain(
            r"\documentclass{wrapper}\usepackage{pkg}\classcall-\pkgcall-\class@mark-\pkg@mark",
        );

        assert_eq!(outcome.output, "class-pkg-\\class@mark-\\pkg@mark");
        assert_eq!(
            outcome
                .diagnostics
                .iter()
                .map(|diagnostic| diagnostic.detail.as_str())
                .collect::<Vec<_>>(),
            vec!["class", "pkg"]
        );
    }

    #[test]
    fn builtin_article_and_package_shims_cover_common_latex_commands() {
        let mut interner = ControlSequenceInterner::new();
        let snapshot = compile_format_snapshot(
            &mut interner,
            r"\def\par{ }\def\begin#1{}\def\end#1{}\def\small{}\def\linewidth{0pt}",
        );
        let mut vm = Vm::restore(&mut interner, &snapshot);

        let outcome = vm.run_plain(
            r"\documentclass{article}\usepackage{hyperref,graphicx,amsmath}\begin{document}\small\href{https://example.test}{Link} \includegraphics[width=\linewidth]{fig} \DeclareMathOperator{\Var}{Var}\Var\end{document}",
        );

        assert!(outcome.output.contains("Link"));
        assert!(outcome.output.contains("[image]"));
        assert!(outcome.output.contains("Var"));
        assert!(
            outcome.diagnostics.is_empty(),
            "unexpected diagnostics: {:?}",
            outcome.diagnostics
        );
        assert!(
            outcome
                .loaded_modules
                .contains(&Utf8PathBuf::from("article.cls"))
        );
        assert!(
            outcome
                .loaded_modules
                .contains(&Utf8PathBuf::from("hyperref.sty"))
        );
    }

    #[test]
    fn render_event_capture_extracts_compact_latex_surface_without_changing_output() {
        let source = r"
\documentclass{article}
\title{A Paper}
\author{Ada Lovelace}
\date{May 1843}
\begin{document}
\maketitle
\begin{abstract}
Short abstract.
\end{abstract}
\section{Intro}
Hello \cite{key}.
\[
  x^2
\]
\begin{thebibliography}{1}
\bibitem{key} Author. Title.
\end{thebibliography}
\begin{unknownenv}
Fallback text.
\end{unknownenv}
\end{document}
";

        let mut baseline_interner = ControlSequenceInterner::new();
        let mut baseline = Vm::new(&mut baseline_interner);
        baseline.set_entry_source_path("main.tex");
        let baseline_outcome = baseline.run_plain(source);

        let mut capture_interner = ControlSequenceInterner::new();
        let mut capture = Vm::new(&mut capture_interner);
        capture.set_entry_source_path("main.tex");
        capture.enable_render_event_capture();
        let captured_outcome = capture.run_plain(source);

        assert_eq!(captured_outcome.output, baseline_outcome.output);
        assert!(captured_outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::SetDocumentMetadata(metadata)
                if metadata.field == MetadataField::Title && metadata.value == "A Paper"
        )));
        assert!(
            captured_outcome
                .render_events
                .iter()
                .any(|event| matches!(&event.event, RenderEvent::FlushTitleBlock(_)))
        );
        let abstract_begin = captured_outcome
            .render_events
            .iter()
            .find(|event| {
                matches!(
                    &event.event,
                    RenderEvent::BeginBlock(block) if block.block == BlockKind::Abstract
                )
            })
            .expect("abstract begin block event");
        assert_eq!(abstract_begin.meta.mode_hint, ModeHint::Vertical);
        let abstract_end = captured_outcome
            .render_events
            .iter()
            .find(|event| {
                matches!(
                    &event.event,
                    RenderEvent::EndBlock(block) if block.block == BlockKind::Abstract
                )
            })
            .expect("abstract end block event");
        assert_eq!(abstract_end.meta.mode_hint, ModeHint::Vertical);
        let hello_text = captured_outcome
            .render_events
            .iter()
            .find(|event| matches!(&event.event, RenderEvent::Text(text) if text.text == "Hello"))
            .expect("hello text event");
        assert_eq!(hello_text.meta.mode_hint, ModeHint::Horizontal);
        let interword_space = captured_outcome
            .render_events
            .iter()
            .find(|event| {
                matches!(
                    &event.event,
                    RenderEvent::Space(space) if space.kind == SpaceKind::Interword
                )
            })
            .expect("interword space event");
        assert_eq!(interword_space.meta.mode_hint, ModeHint::Horizontal);
        assert!(captured_outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineCitation(citation) if citation.keys == vec!["key".to_string()]
        )));
        assert!(captured_outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::RawFallback(fallback)
                if fallback.environment.as_deref() == Some("unknownenv")
                    && fallback.normalized_visible_text.as_deref() == Some("Fallback text.")
        )));
    }

    #[test]
    fn render_event_capture_records_starred_abstract_without_fallback() {
        let source = r"\begin{document}\begin{abstract*}Starred \cite{key} abstract.\end{abstract*}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::BeginBlock(block) if block.block == BlockKind::Abstract
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::EndBlock(block) if block.block == BlockKind::Abstract
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineCitation(citation) if citation.keys == vec!["key".to_string()]
        )));
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::RawFallback(fallback)
                if fallback.environment.as_deref() == Some("abstract*")
        )));
    }

