        let source = r"\begin{document}\begin{longtable}{ll}\caption{Long table.}\label{tab:long}\\ Alpha & Beta\end{longtable}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
