    #[test]
    fn render_event_capture_uses_placeholder_for_tikz_fallback() {
        let cases = [
            ("tikzpicture", "[unsupported tikzpicture]"),
            ("pgfpicture", "[unsupported pgfpicture]"),
        ];

        for (environment, expected) in cases {
            let source = format!(
                r"\begin{{document}}\begin{{{environment}}}\draw (0,0) -- (1,1); \node {{Should not render}};\end{{{environment}}}\end{{document}}"
            );
            let mut interner = ControlSequenceInterner::new();
            let mut vm = Vm::new(&mut interner);
            vm.set_entry_source_path("main.tex");
            vm.enable_render_event_capture();
            let outcome = vm.run_plain(&source);
            let fallback = outcome
                .render_events
                .iter()
                .find_map(|event| match &event.event {
                    RenderEvent::RawFallback(fallback)
                        if fallback.environment.as_deref() == Some(environment) =>
                    {
                        Some(fallback)
                    }
                    _ => None,
                })
                .expect("TikZ fallback event");

            assert_eq!(fallback.normalized_visible_text.as_deref(), Some(expected));
            assert!(fallback.source_excerpt.contains("\\draw"));
            let artifact = fallback
                .full_source_artifact
                .as_deref()
                .expect("full source artifact");
            assert!(artifact.starts_with("fallbacks/"));
            assert!(artifact.ends_with(".tex"));
            assert!(fallback.source_hash.as_deref().is_some_and(|hash| {
                hash.strip_prefix("blake3:")
                    .is_some_and(|digest| artifact == format!("fallbacks/{digest}.tex"))
            }));
            assert!(!fallback.truncated);
            let visible = fallback
                .normalized_visible_text
                .as_deref()
                .unwrap_or_default();
            for hidden in ["draw", "node", "Should not render", "(0,0)", "(1,1)"] {
                assert!(!visible.contains(hidden));
            }
        }
    }

    #[test]
    fn render_event_capture_bounds_raw_fallback_excerpt_by_utf8_bytes() {
        let source = format!(
            r"\begin{{document}}\begin{{unknownenv}}{}\end{{unknownenv}}\end{{document}}",
            "é".repeat(1100)
        );
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(&source);
        let fallback = outcome
            .render_events
            .iter()
            .find_map(|event| match &event.event {
                RenderEvent::RawFallback(fallback)
                    if fallback.environment.as_deref() == Some("unknownenv") =>
                {
                    Some(fallback)
                }
                _ => None,
            })
            .expect("unknownenv fallback");

        assert!(fallback.truncated);
        assert!(
            fallback.source_excerpt.len() <= 2048,
            "source excerpt was {} bytes",
            fallback.source_excerpt.len()
        );
        assert!(matches!(
            fallback.source_hash.as_deref(),
            Some(hash) if hash.starts_with("blake3:")
        ));
        assert!(matches!(
            (
                fallback.source_hash.as_deref(),
                fallback.full_source_artifact.as_deref()
            ),
            (Some(hash), Some(artifact))
                if hash.strip_prefix("blake3:")
                    .is_some_and(|digest| artifact == format!("fallbacks/{digest}.tex"))
        ));
    }

