    #[test]
    fn render_event_capture_records_graphics_and_captions() {
        let source = r"\def\includegraphics[#1]#2{[image]}\def\caption#1{#1}\begin{document}\begin{figure}\includegraphics[width=5cm]{figures/plot.pdf}\caption{Plot caption.}\end{figure}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::BeginBlock(block) if block.block == BlockKind::Figure
        )));
        let graphic_event = outcome
            .render_events
            .iter()
            .find(|event| {
                matches!(
                    &event.event,
                    RenderEvent::GraphicRef(graphic)
                        if graphic.path == "figures/plot.pdf"
                            && graphic.options.as_deref() == Some("width=5cm")
                )
            })
            .expect("graphic event");
        assert_eq!(graphic_event.meta.mode_hint, ModeHint::Vertical);
        assert!(matches!(
            &graphic_event.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                        == r"\includegraphics[width=5cm]{figures/plot.pdf}"
        ));
        assert!(graphic_event.meta.source.related.iter().any(|related| {
            related.role == SourceSpanRole::ArgumentContent
                && matches!(
                    &related.span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == "figures/plot.pdf"
                )
        }));
        let caption_event = outcome
            .render_events
            .iter()
            .find(|event| {
                matches!(
                    &event.event,
                    RenderEvent::Caption(caption) if caption.text == "Plot caption."
                )
            })
            .expect("caption event");
        assert_eq!(caption_event.meta.mode_hint, ModeHint::Vertical);
        assert!(matches!(
            &caption_event.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                        == "Plot caption."
        ));
        assert!(caption_event.meta.source.related.iter().any(|related| {
            related.role == SourceSpanRole::Invocation
                && matches!(
                    &related.span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == r"\caption{Plot caption.}"
                )
        }));
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::RawFallback(fallback)
                if fallback.environment.as_deref() == Some("figure")
        )));
    }

