    #[test]
    fn render_event_capture_records_inline_math() {
        let source = r"\begin{document}Area \(x^2 + y^2\).\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let inline_math = outcome
            .render_events
            .iter()
            .find(|event| matches!(&event.event, RenderEvent::InlineMath(_)))
            .expect("inline math event");

        assert!(matches!(
            &inline_math.event,
            RenderEvent::InlineMath(math)
                if math.raw_source == "x^2 + y^2" && math.normalized_text.is_none()
        ));
        assert_eq!(inline_math.meta.mode_hint, ModeHint::Math);
        assert!(matches!(
            &inline_math.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "x^2 + y^2"
        ));
        assert!(inline_math.meta.source.related.iter().any(|related| {
            related.role == SourceSpanRole::Invocation
                && matches!(
                    &related.span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == r"\(x^2 + y^2\)"
                )
        }));
    }

