    #[test]
    fn render_event_capture_records_heading_levels_and_long_titles() {
        let source = r"\begin{document}\section[Short]{Long Section}\subsection*{Methods}\subsubsection{Details}\paragraph{Sketch}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let headings = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Heading(heading) => Some((heading, &event.meta)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(headings.len(), 4);
        assert_eq!(headings[0].0.level, 1);
        assert_eq!(headings[0].0.text, "Long Section");
        assert_eq!(headings[0].1.mode_hint, ModeHint::Vertical);
        assert!(matches!(
            &headings[0].1.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "Long Section"
        ));
        assert!(headings[0].1.source.related.iter().any(|related| {
            related.role == SourceSpanRole::Invocation
                && matches!(
                    &related.span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == r"\section[Short]{Long Section}"
                )
        }));
        assert_eq!(headings[1].0.level, 2);
        assert_eq!(headings[1].0.text, "Methods");
        assert_eq!(headings[2].0.level, 3);
        assert_eq!(headings[2].0.text, "Details");
        assert_eq!(headings[3].0.level, 4);
        assert_eq!(headings[3].0.text, "Sketch");
    }

    #[test]
    fn render_event_capture_redacts_heading_citation_and_reference_keys() {
        let source = r"\begin{document}\section{See \cite{key} and \ref{sec:intro}.}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let heading_text = outcome
            .render_events
            .iter()
            .find_map(|event| match &event.event {
                RenderEvent::Heading(heading) => Some(heading.text.as_str()),
                _ => None,
            })
            .expect("heading event");

        assert_eq!(heading_text, "See [?] and [?].");
        assert!(!heading_text.contains("key"));
        assert!(!heading_text.contains("sec:intro"));
        assert!(!heading_text.contains("cite"));
        assert!(!heading_text.contains("ref"));
    }

    #[test]
    fn render_event_capture_records_citation_variants() {
        let source = r"\begin{document}\citep[see][p.~3]{alpha,beta}\citet*{gamma}\parencite{delta}\textcite{epsilon}\citep*{zeta}\citealt*{eta}\citealp*{theta}\Textcite*{iota}\Citealt{lambda}\Citealp{mu}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let citations = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineCitation(citation) => Some((citation, &event.meta)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(citations.len(), 10);
        assert_eq!(citations[0].0.command, "citep");
        assert_eq!(citations[0].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(
            citations[0].0.keys,
            vec!["alpha".to_string(), "beta".to_string()]
        );
        assert_eq!(citations[0].1.mode_hint, ModeHint::Horizontal);
        assert!(matches!(
            &citations[0].1.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                        == r"\citep[see][p.~3]{alpha,beta}"
        ));
        assert!(citations[0].1.source.related.iter().any(|related| {
            related.role == tex_render_model::SourceSpanRole::CitationKey
                && matches!(
                    &related.span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == "alpha,beta"
                )
        }));
        assert_eq!(citations[1].0.command, "citet");
        assert_eq!(citations[1].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[1].0.keys, vec!["gamma".to_string()]);
        assert_eq!(citations[2].0.command, "parencite");
        assert_eq!(citations[2].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[2].0.keys, vec!["delta".to_string()]);
        assert_eq!(citations[3].0.command, "textcite");
        assert_eq!(citations[3].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[3].0.keys, vec!["epsilon".to_string()]);
        assert_eq!(citations[4].0.command, "citep");
        assert_eq!(citations[4].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[4].0.keys, vec!["zeta".to_string()]);
        assert_eq!(citations[5].0.command, "citealt");
        assert_eq!(citations[5].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[5].0.keys, vec!["eta".to_string()]);
        assert_eq!(citations[6].0.command, "citealp");
        assert_eq!(citations[6].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[6].0.keys, vec!["theta".to_string()]);
        assert_eq!(citations[7].0.command, "Textcite");
        assert_eq!(citations[7].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[7].0.keys, vec!["iota".to_string()]);
        assert_eq!(citations[8].0.command, "Citealt");
        assert_eq!(citations[8].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[8].0.keys, vec!["lambda".to_string()]);
        assert_eq!(citations[9].0.command, "Citealp");
        assert_eq!(citations[9].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[9].0.keys, vec!["mu".to_string()]);
    }

    #[test]
    fn render_event_capture_records_citation_wrapper_macros() {
        for (source, invocation_text, definition_text, key_text, expected_keys) in [
            (
                r"\newcommand{\mycite}[1]{\cite{#1}}\begin{document}See \mycite{alpha,beta}.\end{document}",
                r"\mycite{alpha,beta}",
                r"\newcommand{\mycite}[1]{\cite{#1}}",
                "alpha,beta",
                &["alpha", "beta"][..],
            ),
            (
                r"\newcommand{\mycite}[2][]{\cite[#1]{#2}}\begin{document}See \mycite[see]{gamma}.\end{document}",
                r"\mycite[see]{gamma}",
                r"\newcommand{\mycite}[2][]{\cite[#1]{#2}}",
                "gamma",
                &["gamma"][..],
            ),
            (
                r"\newcommand{\mycitepair}[2]{\cite{#1,#2}}\begin{document}See \mycitepair{alpha}{beta}.\end{document}",
                r"\mycitepair{alpha}{beta}",
                r"\newcommand{\mycitepair}[2]{\cite{#1,#2}}",
                "alpha}{beta",
                &["alpha", "beta"][..],
            ),
            (
                r"\newcommand{\papercite}[1]{\cite{paper:#1}}\begin{document}See \papercite{one}.\end{document}",
                r"\papercite{one}",
                r"\newcommand{\papercite}[1]{\cite{paper:#1}}",
                "one",
                &["paper:one"][..],
            ),
            (
                r"\newcommand{\corecite}{\cite{core}}\begin{document}See \corecite.\end{document}",
                r"\corecite",
                r"\newcommand{\corecite}{\cite{core}}",
                "core",
                &["core"][..],
            ),
            (
                r"\newcommand{\defaultcite}[1][core]{\cite{#1}}\begin{document}See \defaultcite.\end{document}",
                r"\defaultcite",
                r"\newcommand{\defaultcite}[1][core]{\cite{#1}}",
                "core",
                &["core"][..],
            ),
            (
                r"\newcommand{\mycite}[1]{\cite{#1}}\let\aliascite\mycite\begin{document}See \aliascite{alpha,beta}.\end{document}",
                r"\aliascite{alpha,beta}",
                r"\let\aliascite\mycite",
                "alpha,beta",
                &["alpha", "beta"][..],
            ),
            (
                r"\newcommand{\mycitepair}[2]{\cite{#1,#2}}\let\aliascitepair\mycitepair\begin{document}See \aliascitepair{alpha}{beta}.\end{document}",
                r"\aliascitepair{alpha}{beta}",
                r"\let\aliascitepair\mycitepair",
                "alpha}{beta",
                &["alpha", "beta"][..],
            ),
            (
                r"\newcommand{\papercite}[1]{\cite{paper:#1}}\let\aliaspapercite\papercite\begin{document}See \aliaspapercite{two}.\end{document}",
                r"\aliaspapercite{two}",
                r"\let\aliaspapercite\papercite",
                "two",
                &["paper:two"][..],
            ),
            (
                r"\newcommand{\corecite}{\cite{core}}\let\aliascorecite\corecite\begin{document}See \aliascorecite.\end{document}",
                r"\aliascorecite",
                r"\let\aliascorecite\corecite",
                "core",
                &["core"][..],
            ),
            (
                r"\newcommand{\defaultcite}[1][core]{\cite{#1}}\let\aliasdefaultcite\defaultcite\begin{document}See \aliasdefaultcite.\end{document}",
                r"\aliasdefaultcite",
                r"\let\aliasdefaultcite\defaultcite",
                "core",
                &["core"][..],
            ),
        ] {
            let mut interner = ControlSequenceInterner::new();
            let mut vm = Vm::new(&mut interner);
            vm.set_entry_source_path("main.tex");
            vm.enable_render_event_capture();
            let outcome = vm.run_plain(source);
            let citation = outcome
                .render_events
                .iter()
                .find(|event| matches!(&event.event, RenderEvent::InlineCitation(_)))
                .expect("citation event");

            assert!(matches!(
                &citation.event,
                RenderEvent::InlineCitation(citation)
                    if citation.command == "cite"
                        && citation.style_hint == CitationStyleHint::Numeric
                        && citation.keys
                            == expected_keys
                                .iter()
                                .map(|key| key.to_string())
                                .collect::<Vec<_>>()
            ));
            assert!(matches!(
                &citation.meta.source.primary,
                tex_render_model::ProvenanceSpan::File(span)
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == invocation_text
            ));
            assert!(citation.meta.source.related.iter().any(|related| {
                related.role == SourceSpanRole::CitationKey
                    && matches!(
                        &related.span,
                        tex_render_model::ProvenanceSpan::File(span)
                            if span.path == Utf8PathBuf::from("main.tex")
                                && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                    == key_text
                    )
            }));
            assert!(matches!(
                &citation.meta.source.expansion_stack[0].definition_span,
                Some(tex_render_model::ProvenanceSpan::File(span))
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == definition_text
            ));
            assert!(!outcome.render_events.iter().any(|event| matches!(
                &event.event,
                RenderEvent::Text(text) if expected_keys.iter().any(|key| text.text.contains(key))
            )));
        }
    }

    #[test]
    fn render_event_capture_records_citation_metadata_aliases_without_leaking_keys() {
        let source = r"\begin{document}\Citeauthor{alpha} \Citeyear{beta} \Citeyearpar{gamma} \citetitle{delta} \Citetitle{epsilon} \citefullauthor{zeta} \Citefullauthor*{eta}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let citations = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineCitation(citation) => Some(citation),
                _ => None,
            })
            .collect::<Vec<_>>();

        let expected = [
            ("Citeauthor", "alpha", CitationStyleHint::Textual),
            ("Citeyear", "beta", CitationStyleHint::Textual),
            ("Citeyearpar", "gamma", CitationStyleHint::Parenthetical),
            ("citetitle", "delta", CitationStyleHint::Textual),
            ("Citetitle", "epsilon", CitationStyleHint::Textual),
            ("citefullauthor", "zeta", CitationStyleHint::Textual),
            ("Citefullauthor", "eta", CitationStyleHint::Textual),
        ];
        assert_eq!(citations.len(), expected.len());
        for (citation, (command, key, style_hint)) in citations.iter().zip(expected) {
            assert_eq!(citation.command, command);
            assert_eq!(citation.keys, vec![key.to_string()]);
            assert_eq!(citation.style_hint, style_hint);
        }
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::Text(text)
                if text.text.contains("alpha")
                    || text.text.contains("beta")
                    || text.text.contains("gamma")
                    || text.text.contains("delta")
                    || text.text.contains("epsilon")
                    || text.text.contains("zeta")
                    || text.text.contains("eta")
        )));
    }

