    #[test]
    fn render_event_capture_records_references_without_leaking_keys() {
        let source = r"\begin{document}See \ref{sec:intro} and \eqref{eq:main}; \cref{fig:a,tab:b}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let references = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineReference(reference) => Some((reference, &event.meta)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(references.len(), 3);
        for (_, meta) in &references {
            assert_eq!(meta.mode_hint, ModeHint::Horizontal);
        }
        assert_eq!(references[0].0.command, "ref");
        assert_eq!(references[0].0.keys, vec!["sec:intro".to_string()]);
        assert!(matches!(
            &references[0].1.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == r"\ref{sec:intro}"
        ));
        assert!(references[0].1.source.related.iter().any(|related| {
            related.role == tex_render_model::SourceSpanRole::ReferenceKey
                && matches!(
                    &related.span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == "sec:intro"
                )
        }));
        assert_eq!(references[1].0.command, "eqref");
        assert_eq!(references[1].0.keys, vec!["eq:main".to_string()]);
        assert_eq!(references[2].0.command, "cref");
        assert_eq!(
            references[2].0.keys,
            vec!["fig:a".to_string(), "tab:b".to_string()]
        );
    }

    #[test]
    fn render_event_capture_records_reference_wrapper_macros() {
        for (
            source,
            invocation_text,
            definition_text,
            key_source_text,
            expected_key,
            expected_command,
        ) in [
            (
                r"\newcommand{\myref}[1]{\ref{#1}}\begin{document}See \myref{sec:intro}.\end{document}",
                r"\myref{sec:intro}",
                r"\newcommand{\myref}[1]{\ref{#1}}",
                "sec:intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\secref}[1]{\ref{sec:#1}}\begin{document}See \secref{intro}.\end{document}",
                r"\secref{intro}",
                r"\newcommand{\secref}[1]{\ref{sec:#1}}",
                "intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\introref}{\ref{sec:intro}}\begin{document}See \introref.\end{document}",
                r"\introref",
                r"\newcommand{\introref}{\ref{sec:intro}}",
                "sec:intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\defaultref}[1][sec:intro]{\ref{#1}}\begin{document}See \defaultref.\end{document}",
                r"\defaultref",
                r"\newcommand{\defaultref}[1][sec:intro]{\ref{#1}}",
                "sec:intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\myautoref}[2][]{\autoref{#2}}\begin{document}See \myautoref[Section]{sec:auto}.\end{document}",
                r"\myautoref[Section]{sec:auto}",
                r"\newcommand{\myautoref}[2][]{\autoref{#2}}",
                "sec:auto",
                "sec:auto",
                "autoref",
            ),
            (
                r"\newcommand{\myref}[1]{\ref{#1}}\let\aliasref\myref\begin{document}See \aliasref{sec:intro}.\end{document}",
                r"\aliasref{sec:intro}",
                r"\let\aliasref\myref",
                "sec:intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\secref}[1]{\ref{sec:#1}}\let\aliassecref\secref\begin{document}See \aliassecref{intro}.\end{document}",
                r"\aliassecref{intro}",
                r"\let\aliassecref\secref",
                "intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\introref}{\ref{sec:intro}}\let\aliasintroref\introref\begin{document}See \aliasintroref.\end{document}",
                r"\aliasintroref",
                r"\let\aliasintroref\introref",
                "sec:intro",
                "sec:intro",
                "ref",
            ),
            (
                r"\newcommand{\defaultref}[1][sec:intro]{\ref{#1}}\let\aliasdefaultref\defaultref\begin{document}See \aliasdefaultref.\end{document}",
                r"\aliasdefaultref",
                r"\let\aliasdefaultref\defaultref",
                "sec:intro",
                "sec:intro",
                "ref",
            ),
        ] {
            let mut interner = ControlSequenceInterner::new();
            let mut vm = Vm::new(&mut interner);
            vm.set_entry_source_path("main.tex");
            vm.enable_render_event_capture();
            let outcome = vm.run_plain(source);
            let reference = outcome
                .render_events
                .iter()
                .find(|event| matches!(&event.event, RenderEvent::InlineReference(_)))
                .expect("reference event");

            assert!(matches!(
                &reference.event,
                RenderEvent::InlineReference(reference)
                    if reference.command == expected_command
                        && reference.keys == vec![expected_key.to_string()]
            ));
            assert!(matches!(
                &reference.meta.source.primary,
                tex_render_model::ProvenanceSpan::File(span)
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == invocation_text
            ));
            assert!(reference.meta.source.related.iter().any(|related| {
                related.role == SourceSpanRole::ReferenceKey
                    && matches!(
                        &related.span,
                        tex_render_model::ProvenanceSpan::File(span)
                            if span.path == Utf8PathBuf::from("main.tex")
                                && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                    == key_source_text
                    )
            }));
            assert!(matches!(
                &reference.meta.source.expansion_stack[0].definition_span,
                Some(tex_render_model::ProvenanceSpan::File(span))
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == definition_text
            ));
            assert!(!outcome.render_events.iter().any(|event| matches!(
                &event.event,
                RenderEvent::Text(text) if text.text.contains(expected_key)
            )));
        }
    }

    #[test]
    fn render_event_capture_records_reference_range_wrapper_macros() {
        for (source, invocation_text, definition_text) in [
            (
                r"\newcommand{\myrange}[2]{\crefrange{#1}{#2}}\begin{document}See \myrange{fig:a}{fig:b}.\end{document}",
                r"\myrange{fig:a}{fig:b}",
                r"\newcommand{\myrange}[2]{\crefrange{#1}{#2}}",
            ),
            (
                r"\newcommand{\myrange}[2]{\crefrange{#1}{#2}}\let\aliasrange\myrange\begin{document}See \aliasrange{fig:a}{fig:b}.\end{document}",
                r"\aliasrange{fig:a}{fig:b}",
                r"\let\aliasrange\myrange",
            ),
        ] {
            let mut interner = ControlSequenceInterner::new();
            let mut vm = Vm::new(&mut interner);
            vm.set_entry_source_path("main.tex");
            vm.enable_render_event_capture();
            let outcome = vm.run_plain(source);
            let reference = outcome
                .render_events
                .iter()
                .find(|event| matches!(&event.event, RenderEvent::InlineReference(_)))
                .expect("reference event");

            assert!(matches!(
                &reference.event,
                RenderEvent::InlineReference(reference)
                    if reference.command == "crefrange"
                        && reference.keys == vec!["fig:a".to_string(), "fig:b".to_string()]
            ));
            assert!(matches!(
                &reference.meta.source.primary,
                tex_render_model::ProvenanceSpan::File(span)
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == invocation_text
            ));
            assert!(reference.meta.source.related.iter().any(|related| {
                related.role == SourceSpanRole::ReferenceKey
                    && matches!(
                        &related.span,
                        tex_render_model::ProvenanceSpan::File(span)
                            if span.path == Utf8PathBuf::from("main.tex")
                                && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                    == "fig:a}{fig:b"
                    )
            }));
            assert!(matches!(
                &reference.meta.source.expansion_stack[0].definition_span,
                Some(tex_render_model::ProvenanceSpan::File(span))
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == definition_text
            ));
            assert!(!outcome.render_events.iter().any(|event| matches!(
                &event.event,
                RenderEvent::Text(text)
                    if text.text.contains("fig:a") || text.text.contains("fig:b")
            )));
        }
    }

