    #[test]
    fn render_event_capture_redacts_link_text_citation_and_reference_keys() {
        let source = r"\begin{document}Read \href{https://hidden.test}{see \cite{cited}, \citep*{starred}, \ref{sec:intro}, and \ref*{sec:starred}}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let link = outcome
            .render_events
            .iter()
            .find_map(|event| match &event.event {
                RenderEvent::InlineLink(link) => Some(link),
                _ => None,
            })
            .expect("link event");

        assert_eq!(link.target, "https://hidden.test");
        assert_eq!(link.text, "see [?], [?], [?], and [?]");
        assert!(!link.text.contains("cited"));
        assert!(!link.text.contains("starred"));
        assert!(!link.text.contains("sec:intro"));
        assert!(!link.text.contains("sec:starred"));
        assert!(!link.text.contains("cite"));
        assert!(!link.text.contains("ref"));
    }

    #[test]
    fn render_event_capture_records_url_text_wrappers_without_link_annotations() {
        let source = r"\begin{document}Use \nolinkurl{https://example.test/paper}, \nolinkurl|https://example.test/delimited|, at \path{/tmp/archive} and \path|/var/tmp| via \detokenize{\foo+*}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let text_events = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Text(text) => Some((&text.text, &event.meta.source.primary)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert!(text_events.iter().any(|(text, span)| {
            text.as_str() == "https://example.test/paper"
                && matches!(
                    span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == "https://example.test/paper"
                )
        }));
        assert!(
            text_events
                .iter()
                .any(|(text, _)| text.as_str() == "/tmp/archive")
        );
        assert!(text_events.iter().any(|(text, span)| {
            text.as_str() == "https://example.test/delimited"
                && matches!(
                    span,
                    tex_render_model::ProvenanceSpan::File(span)
                        if span.path == Utf8PathBuf::from("main.tex")
                            && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                == "https://example.test/delimited"
                )
        }));
        assert!(
            text_events
                .iter()
                .any(|(text, _)| text.as_str() == "/var/tmp")
        );
        assert!(
            text_events
                .iter()
                .any(|(text, _)| text.as_str() == r"\foo+*")
        );
        assert!(
            !outcome
                .render_events
                .iter()
                .any(|event| matches!(&event.event, RenderEvent::InlineLink(_)))
        );
    }

