    #[test]
    fn render_event_capture_skips_cyclic_input_files_once() {
        let source = r"\begin{document}Root start. \input{child} Root end.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.mount_file("child.tex", r"Child start. \input{child} Child end.");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        let visible_text = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Text(text) => Some(text.text.as_str()),
                RenderEvent::Space(_) => Some(" "),
                _ => None,
            })
            .collect::<Vec<_>>()
            .join("");

        assert_eq!(visible_text.matches("Child start.").count(), 1);
        assert_eq!(visible_text.matches("Child end.").count(), 1);
        assert!(visible_text.contains("Root start."));
        assert!(visible_text.contains("Root end."));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::Diagnostic(diagnostic) if diagnostic.message.contains("cyclic")
        )));
        assert!(outcome.diagnostics.iter().any(|diagnostic| {
            diagnostic.kind == VmDiagnosticKind::ExplicitError
                && diagnostic.detail.contains("cyclic")
        }));
    }

    #[test]
    fn render_event_capture_records_nested_wrapper_unknown_command_inline_events() {
        let source = r"\begin{document}Nested \emph{before \unknowntext{see \cite{key}, \citep*{starred}, \ref{sec:intro}, \crefrange*{fig:a}{fig:b}, and \ref*{sec:starred}} after}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineCitation(citation) if citation.keys == vec!["key".to_string()]
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineCitation(citation)
                if citation.keys == vec!["starred".to_string()]
                    && citation.command == "citep"
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineReference(reference)
                if reference.keys == vec!["sec:intro".to_string()]
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineReference(reference)
                if reference.keys == vec!["fig:a".to_string(), "fig:b".to_string()]
                    && reference.command == "crefrange"
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineReference(reference)
                if reference.keys == vec!["sec:starred".to_string()]
                    && reference.command == "ref"
        )));

        let visible_text = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Text(text) => Some(text.text.as_str()),
                RenderEvent::Space(_) => Some(" "),
                _ => None,
            })
            .collect::<Vec<_>>()
            .join("");

        assert!(visible_text.contains("Nested before see "));
        assert!(visible_text.contains(" after."));
        assert!(!visible_text.contains("unknowntext"));
        assert!(!visible_text.contains("{see"));
        assert!(!visible_text.contains("key"));
        assert!(!visible_text.contains("starred"));
        assert!(!visible_text.contains("sec:intro"));
        assert!(!visible_text.contains("fig:a"));
        assert!(!visible_text.contains("fig:b"));
        assert!(!visible_text.contains("sec:starred"));
    }

    #[test]
    fn render_event_capture_records_nested_wrapper_unknown_command_links_and_math() {
        let source = r"\begin{document}Nested \emph{before \unknowntext{see \href{https://hidden.test}{paper}, \url{https://shown.test}, and $x^2$} after}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let links = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineLink(link) => Some(link),
                _ => None,
            })
            .collect::<Vec<_>>();
        let math = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineMath(math) => Some(math.raw_source.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert!(links.iter().any(|link| {
            link.target == "https://hidden.test" && link.text == "paper" && link.command == "href"
        }));
        assert!(links.iter().any(|link| {
            link.target == "https://shown.test"
                && link.text == "https://shown.test"
                && link.command == "url"
        }));
        assert!(math.contains(&"x^2"));

        let visible_text = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Text(text) => Some(text.text.as_str()),
                RenderEvent::Space(_) => Some(" "),
                _ => None,
            })
            .collect::<Vec<_>>()
            .join("");

        assert!(visible_text.contains("Nested before see "));
        assert!(visible_text.contains(", "));
        assert!(visible_text.contains(" and "));
        assert!(visible_text.contains(" after."));
        assert!(!visible_text.contains("unknowntext"));
        assert!(!visible_text.contains("https://hidden.test"));
        assert!(!visible_text.contains("{paper}"));
        assert!(!visible_text.contains("$x^2$"));
    }

