    #[test]
    fn render_event_capture_loads_siunitx_package_shim_and_renders_units() {
        let source = r"\documentclass{article}\usepackage{siunitx}\sisetup{detect-all}\begin{document}Speed \SI{3.5}{m/s}; count \num{1200}; unit \si{kg}; range \SIrange{1}{2}{m}; macro \SI{9}{\meter\per\second}; freq \SI{5}{\kilo\hertz}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(!outcome.diagnostics.iter().any(|diagnostic| {
            diagnostic.kind == VmDiagnosticKind::MissingFile
                && diagnostic.detail == "package siunitx.sty"
        }));
        assert!(!outcome.diagnostics.iter().any(|diagnostic| {
            diagnostic.kind == VmDiagnosticKind::UndefinedControlSequence
                && matches!(
                    diagnostic.detail.as_str(),
                    "sisetup" | "SI" | "num" | "si" | "SIrange"
                )
        }));
        assert!(
            outcome
                .loaded_modules
                .contains(&Utf8PathBuf::from("siunitx.sty"))
        );

        let visible_text = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Text(text) => Some(text.text.as_str()),
                RenderEvent::Space(_) => Some(" "),
                _ => None,
            })
            .collect::<Vec<_>>()
            .join("");
        for visible in [
            "Speed 3.5 m/s",
            "count 1200",
            "unit kg",
            "range 1--2 m",
            "macro 9 m/s",
            "freq 5 kHz",
        ] {
            assert!(
                visible_text.contains(visible),
                "visible text missing {visible:?}: {visible_text:?}"
            );
        }
        for hidden in [
            r"\SI",
            r"\num",
            r"\si",
            r"\SIrange",
            r"\meter",
            r"\hertz",
            "sisetup",
            "{3.5}",
            "{m/s}",
        ] {
            assert!(!visible_text.contains(hidden));
        }
    }

    #[test]
    fn render_event_capture_loads_table_helper_package_shims() {
        let source = r"\documentclass{article}\usepackage{subeqnarray}\usepackage{diagbox}\usepackage{slashbox}\usepackage{makecell}\usepackage{multirow}\begin{document}\begin{tabular}{cccc}\diagbox{Rows}{Cols} & \backslashbox{Old}{New} & \makecell*{Cell \cite{key}} & \multirow{2}{*}{Span} \\\thead*{Head} & \slashbox{Left}{Right} & \multirowcell{2}{Body} & Tail\end{tabular}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        for package in [
            "subeqnarray.sty",
            "diagbox.sty",
            "slashbox.sty",
            "makecell.sty",
            "multirow.sty",
        ] {
            assert!(!outcome.diagnostics.iter().any(|diagnostic| {
                diagnostic.kind == VmDiagnosticKind::MissingFile
                    && diagnostic.detail == format!("package {package}")
            }));
            assert!(outcome.loaded_modules.contains(&Utf8PathBuf::from(package)));
        }
        assert!(!outcome.diagnostics.iter().any(|diagnostic| {
            diagnostic.kind == VmDiagnosticKind::UndefinedControlSequence
                && matches!(
                    diagnostic.detail.as_str(),
                    "diagbox"
                        | "slashbox"
                        | "backslashbox"
                        | "makecell"
                        | "thead"
                        | "multirow"
                        | "multirowcell"
                )
        }));
        let visible_text = outcome
            .render_events
            .iter()
            .find_map(|event| match &event.event {
                RenderEvent::RawFallback(fallback)
                    if fallback.environment.as_deref() == Some("tabular") =>
                {
                    fallback.normalized_visible_text.as_deref()
                }
                _ => None,
            })
            .expect("tabular fallback visible text");
        for visible in [
            "Rows/Cols",
            "Old/New",
            "Left/Right",
            "Cell [?]",
            "Span",
            "Head",
            "Body",
            "Tail",
        ] {
            assert!(
                visible_text.contains(visible),
                "visible text missing {visible:?}: {visible_text:?}"
            );
        }
        assert!(!visible_text.contains("makecell"));
        assert!(!visible_text.contains("thead"));
        assert!(!visible_text.contains("slashbox"));
        assert!(!visible_text.contains("backslashbox"));
    }

