    #[test]
    fn render_event_capture_records_direct_inline_command_aliases() {
        let source = r"\let\mycite\cite\let\myref\ref\let\myrange\crefrange\let\myhref\href\let\mylabel\label\begin{document}\section{Intro}\mylabel{sec:intro}See \mycite{key}, \myref{sec:intro}, \myrange{fig:a}{fig:b}, and \myhref{https://hidden.test}{paper link}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineCitation(citation)
                if citation.command == "cite" && citation.keys == vec!["key".to_string()]
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineReference(reference)
                if reference.command == "ref" && reference.keys == vec!["sec:intro".to_string()]
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineReference(reference)
                if reference.command == "crefrange"
                    && reference.keys == vec!["fig:a".to_string(), "fig:b".to_string()]
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::InlineLink(link)
                if link.command == "href"
                    && link.target == "https://hidden.test"
                    && link.text == "paper link"
        )));
        assert!(outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::LabelDefinition(label)
                if label.command == "label" && label.key == "sec:intro"
        )));
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::Text(text)
                if text.text.contains("key")
                    || text.text.contains("sec:intro")
                    || text.text.contains("fig:a")
                    || text.text.contains("fig:b")
                    || text.text.contains("https://hidden.test")
        )));
    }

    #[test]
    fn render_event_capture_records_section_macro_provenance() {
        for (source, heading_text, invocation_text, command_name, level) in [
            (
                r"\newcommand{\mysection}[1]{\section{#1}}\begin{document}\mysection{Intro}\end{document}",
                "Intro",
                r"\mysection{Intro}",
                "mysection",
                1,
            ),
            (
                r"\newcommand{\mysubsection}[1]{\subsection{#1}}\begin{document}\mysubsection{Details}\end{document}",
                "Details",
                r"\mysubsection{Details}",
                "mysubsection",
                2,
            ),
        ] {
            let mut interner = ControlSequenceInterner::new();
            let mut vm = Vm::new(&mut interner);
            vm.set_entry_source_path("main.tex");
            vm.enable_render_event_capture();
            let outcome = vm.run_plain(source);
            let heading = outcome
                .render_events
                .iter()
                .find(|event| {
                    matches!(&event.event, RenderEvent::Heading(heading) if heading.text == heading_text)
                })
                .expect("heading event");

            assert!(matches!(
                &heading.event,
                RenderEvent::Heading(heading) if heading.level == level
            ));
            assert!(matches!(
                &heading.meta.source.primary,
                tex_render_model::ProvenanceSpan::File(span)
                    if span.path == Utf8PathBuf::from("main.tex")
                        && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                            == heading_text
            ));
            assert!(heading.meta.source.related.iter().any(|related| {
                related.role == SourceSpanRole::Invocation
                    && matches!(
                        &related.span,
                        tex_render_model::ProvenanceSpan::File(span)
                            if span.path == Utf8PathBuf::from("main.tex")
                                && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                                    == invocation_text
                    )
            }));
            assert_eq!(heading.meta.source.expansion_stack.len(), 1);
            assert_eq!(
                heading.meta.source.expansion_stack[0]
                    .command_name
                    .as_deref(),
                Some(command_name)
            );
            assert!(
                heading.meta.source.expansion_stack[0]
                    .definition_span
                    .is_some()
            );
        }
    }

